#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
fix_klaxmap_bkp_dashboard_layout.py

Limpieza del Dashboard BKP de klaxmap:
- Quita contenedores redundantes:
  * "Como interactuan los modulos"
  * "Modulos BKP" grande
  * "Operacion y recuperacion" separado
- Deja una estructura clara:
  * Hero con siguiente paso
  * KPIs compactos
  * Configuracion guiada + Alertas/Acciones rapidas
  * Ultimas ejecuciones
- Alinea contenedores y reduce descuadres/espacios innecesarios.

Ejecutar desde la raiz de klaxmap:
    python3 fix_klaxmap_bkp_dashboard_layout.py

Luego:
    npm run build
"""

from __future__ import annotations

import datetime as _dt
import shutil
import sys
from pathlib import Path

ROOT = Path.cwd()
BACKUP_DIR = ROOT / ".bkp_dashboard_layout_backup" / _dt.datetime.now().strftime("%Y%m%d_%H%M%S")

